"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[34],{99939:e=>{e.exports=JSON.parse('{"functions":[{"name":"new","desc":"Creates a new BulletContext.\\n\\n`Origin`, `Direction`, and `Speed` are required. `Callbacks` and `SolverData`\\nare optional and primarily used internally.","params":[{"name":"config","desc":"","lua_type":"BulletContextConfig"}],"returns":[{"desc":"","lua_type":"BulletContext"}],"function_type":"static","source":{"line":134,"path":"docs/BulletContext.lua"}},{"name":"IsAlive","desc":"Returns whether the bullet is still alive and being simulated.","params":[],"returns":[{"desc":"","lua_type":"boolean"}],"function_type":"method","source":{"line":143,"path":"docs/BulletContext.lua"}},{"name":"GetLifetime","desc":"Returns how many seconds have elapsed since the bullet was created.","params":[],"returns":[{"desc":"Age in seconds.","lua_type":"number"}],"function_type":"method","source":{"line":150,"path":"docs/BulletContext.lua"}},{"name":"GetDistanceTraveled","desc":"Returns the straight-line distance from [BulletContext.Origin] to the current\\n[BulletContext.Position]. Note: this is not the same as [BulletContext.Length],\\nwhich accumulates the actual curved path length.","params":[],"returns":[{"desc":"Distance in studs, or 0 if no position is recorded yet.","lua_type":"number"}],"function_type":"method","source":{"line":159,"path":"docs/BulletContext.lua"}},{"name":"GetSnapshot","desc":"Returns a read-only snapshot of the bullet\'s current state.\\n\\nUseful for logging, replication, or passing state to systems that should\\nnot hold a live reference to the context.","params":[],"returns":[{"desc":"","lua_type":"BulletSnapshot"}],"function_type":"method","source":{"line":169,"path":"docs/BulletContext.lua"}},{"name":"Terminate","desc":"Terminates the bullet immediately, notifying the solver to clean up resources,\\ndestroy the cosmetic object, and fire `OnTerminated`.\\n\\nCalling `Terminate` on an already-dead bullet is a no-op.","params":[],"returns":[],"function_type":"method","source":{"line":177,"path":"docs/BulletContext.lua"}}],"properties":[{"name":"Id","desc":"Auto-incrementing unique identifier assigned at construction time.\\nUse this to distinguish bullets in signal handlers without storing separate references.","lua_type":"number","readonly":true,"source":{"line":39,"path":"docs/BulletContext.lua"}},{"name":"Origin","desc":"World-space muzzle position at the moment the bullet was fired. Never changes.","lua_type":"Vector3","readonly":true,"source":{"line":47,"path":"docs/BulletContext.lua"}},{"name":"Direction","desc":"Unit direction vector the bullet was fired along. Never changes.","lua_type":"Vector3","readonly":true,"source":{"line":55,"path":"docs/BulletContext.lua"}},{"name":"Speed","desc":"Initial speed in studs per second. The bullet\'s actual speed decreases over\\ntime due to bounces (restitution) and pierces (speed retention).","lua_type":"number","readonly":true,"source":{"line":64,"path":"docs/BulletContext.lua"}},{"name":"StartTime","desc":"`os.clock()` timestamp at construction. Use with [BulletContext:GetLifetime] to\\ncompute bullet age without storing the time yourself.","lua_type":"number","readonly":true,"source":{"line":73,"path":"docs/BulletContext.lua"}},{"name":"Position","desc":"Current world-space position. Updated every frame by the solver. `nil` until the\\nfirst simulation step.","lua_type":"Vector3?","readonly":true,"source":{"line":82,"path":"docs/BulletContext.lua"}},{"name":"Velocity","desc":"Current velocity vector in studs per second. Updated every frame by the solver.\\nThe magnitude of this vector is the current speed.","lua_type":"Vector3","readonly":true,"source":{"line":91,"path":"docs/BulletContext.lua"}},{"name":"Alive","desc":"`true` while the cast is being simulated. Set to `false` by [BulletContext:Terminate]\\nor automatically by the solver on hit, distance expiry, or speed expiry.","lua_type":"boolean","readonly":true,"source":{"line":100,"path":"docs/BulletContext.lua"}},{"name":"Length","desc":"Cumulative distance the bullet has travelled along its actual ray path, in studs.","lua_type":"number","readonly":true,"source":{"line":108,"path":"docs/BulletContext.lua"}},{"name":"UserData","desc":"Free-form table for attaching cast-specific metadata (shooter UserId, weapon type,\\ndamage value, etc.). Surfaced on every signal emission \u2014 read it in your handlers\\nto route events without maintaining a parallel lookup.\\n\\n```lua\\ncontext.UserData.Damage   = 45\\ncontext.UserData.ShooterId = Players.LocalPlayer.UserId\\n```","lua_type":"{[any]: any}","source":{"line":122,"path":"docs/BulletContext.lua"}}],"types":[],"name":"BulletContext","desc":"The public-facing object that weapon code interacts with for every in-flight projectile.\\n\\nCreate one before firing, pass it to [HybridSolver:Fire], then use the module-level\\nsignals to react to events. The context is passed as the first argument on every signal\\nso you can identify the bullet and read its current state.\\n\\n```lua\\nlocal context = BulletContext.new({\\n    Origin    = muzzlePosition,\\n    Direction = direction,\\n    Speed     = 200,\\n    SolverData = {},\\n})\\n\\nSolver:Fire(context, Behavior)\\n```\\n\\n:::tip UserData\\nAttach weapon-specific metadata (shooter UserId, damage value, hit-group flags, etc.)\\nvia `context.UserData` before calling `Fire`. This table is passed unchanged on every\\nsignal emission.\\n:::","source":{"line":27,"path":"docs/BulletContext.lua"}}')}}]);